def naive_bayes_train(X, y):
    classes = {}
    for label in set(y):
        classes[label] = {'count': y.count(label), 'features': {}}

    for i, sample in enumerate(X):
        label = y[i]
        for j, feature in enumerate(sample):
            if j not in classes[label]['features']:
                classes[label]['features'][j] = {}
            classes[label]['features'][j][feature] = classes[label]['features'][j].get(feature, 0) + 1

    return classes

def naive_bayes_predict(model, x):
    best_label, best_prob = None, -1
    total_samples = sum(model[label]['count'] for label in model)

    for label in model:
        prob = model[label]['count'] / total_samples
        for i, feature in enumerate(x):
            feature_counts = model[label]['features'].get(i, {})
            total_feature = sum(feature_counts.values())
            prob *= (feature_counts.get(feature, 0) + 1) / (total_feature + len(feature_counts))

        if prob > best_prob:
            best_prob, best_label = prob, label

    return best_label

