import re
from collections import Counter, defaultdict

class BPETokenizer:
    def __init__(self, vocab_size=50):
        self.vocab_size = vocab_size
        self.vocab = {}
        self.merges = {}
        self.special_tokens = ['<PAD>', '<UNK>', '<BOS>', '<EOS>']

    def get_stats(self, words):
        pairs = defaultdict(int)
        for word, freq in words.items():
            symbols = word.split()
            for i in range(len(symbols)-1):
                pairs[(symbols[i], symbols[i+1])] += freq
        return pairs

    def merge_vocab(self, pair, words):
        new_words = {}
        bigram = ' '.join(pair)
        replacement = ''.join(pair)

        for word, freq in words.items():
            new_word = word.replace(bigram, replacement)
            new_words[new_word] = freq
        return new_words

    def fit(self, texts):
        # İlkin söz lüğəti
        words = {}
        for text in texts:
            for word in text.lower().split():
                word_with_space = ' '.join(list(word)) + ' </w>'
                words[word_with_space] = words.get(word_with_space, 0) + 1

        # İlkin simvol lüğəti
        chars = set()
        for word in words:
            for char in word.split():
                chars.add(char)

        self.vocab = {}
        for i, char in enumerate(sorted(chars)):
            self.vocab[char] = i + len(self.special_tokens)

        # BPE təkrarları
        num_merges = self.vocab_size - len(self.vocab) - len(self.special_tokens)

        for i in range(num_merges):
            pairs = self.get_stats(words)
            if not pairs:
                break

            best_pair = max(pairs, key=pairs.get)
            words = self.merge_vocab(best_pair, words)

            merged = ''.join(best_pair)
            self.merges[best_pair] = merged
            self.vocab[merged] = len(self.vocab) + len(self.special_tokens)

        return self

    def encode(self, text):
        tokens = []
        for word in text.lower().split():
            word = word + '</w>'
            symbols = list(word)

            changed = True
            while changed and len(symbols) > 1:
                changed = False
                for i in range(len(symbols)-1):
                    pair = (symbols[i], symbols[i+1])
                    if pair in self.merges:
                        symbols = symbols[:i] + [self.merges[pair]] + symbols[i+2:]
                        changed = True
                        break

            for symbol in symbols:
                if symbol in self.vocab:
                    tokens.append(self.vocab[symbol])
                else:
                    tokens.append(1)  # <UNK>

        return tokens

    def decode(self, tokens):
        idx_to_token = {idx: token for token, idx in self.vocab.items()}

        text = ''
        for token in tokens:
            if token in idx_to_token:
                token_str = idx_to_token[token]
                token_str = token_str.replace('</w>', ' ')
                text += token_str
            else:
                text += '<UNK> '

        return text.strip()

